<style>
#aviation-preloader {
    position: fixed;
    top: 0;
    left: 0;
    z-index: 999999;
    width: 100%;
    height: 100%;
    background-color: #ffffff;
    display: flex;
    align-items: center;
    justify-content: center;
    overflow: hidden;
}

/* Container for rotation */
.loader-svg-container {
    width: 150px;
    height: 150px;
    animation: rotate 2s linear infinite;
    display: flex;
    align-items: center;
    justify-content: center;
}

.loader-svg-container svg {
    width: 100%;
    height: 100%;
}

@keyframes rotate {
    from {
        transform: rotate(0deg);
    }
    to {
        transform: rotate(360deg);
    }
}
</style>

<script>
document.addEventListener('DOMContentLoaded', function() {
    // Hide loader on window load mimicking original behavior
    window.addEventListener('load', function() {
        var loader = document.getElementById('aviation-preloader');
        if (loader) {
            setTimeout(function() {
                loader.style.opacity = '0';
                loader.style.transition = 'opacity 0.6s ease';
                setTimeout(function() {
                    loader.style.display = 'none';
                }, 600);
            }, 500);
        }
    });
});
</script>
